    let logger = Arc::new(logger);

    b.iter(|| {
        let handles: Vec<_> = (0..4).map(|_| {
            let l = logger.clone();
            thread::spawn(move || {
                for _ in 0..100 {
                    l.info("benchmark", &[]);
                }
            })
        }).collect();
        for h in handles {
            h.join().unwrap();
        }
    });
}
